import{_ as t,o as r,c as e,ae as o}from"./chunks/framework.DAK3ioSj.js";const c=JSON.parse('{"title":"MetaClaw","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-metaclaw.md","filePath":"radar/tech-metaclaw.md"}'),l={name:"radar/tech-metaclaw.md"};function n(i,a,s,h,d,u){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="metaclaw" tabindex="-1">MetaClaw <a class="header-anchor" href="#metaclaw" aria-label="Permalink to &quot;MetaClaw&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 优化 | <strong>成熟度</strong>: 🟢 成熟期 | <strong>综合评分</strong>: 0.65</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: <strong>双环架构</strong>（Fast Loop 秒级 Skill 进化 + Slow Loop 小时级 LoRA 微调）实现 7×24 生产 Agent 的<strong>零停机持续进化</strong>。</p><p><strong>来源</strong>:</p><ul><li>学术 + OpenClaw 生态（3.5K+ ★）</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2603.17187" target="_blank" rel="noreferrer">arXiv 2603.17187</a></li><li>GitHub：<a href="https://github.com/aiming-lab/MetaClaw" target="_blank" rel="noreferrer">aiming-lab/MetaClaw</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="fast-loop-秒级" tabindex="-1">Fast Loop（秒级） <a class="header-anchor" href="#fast-loop-秒级" aria-label="Permalink to &quot;Fast Loop（秒级）&quot;">​</a></h3><p>Agent 执行失败 → LLM Evolver 立即分析失败轨迹 → 诊断根因 → 合成新 Skill → 即时生效。<strong>零停机</strong>。</p><p>例：Agent 处理一种新格式日志失败 → 几秒内生成&quot;新日志格式解析&quot;Skill 并注入 → 下个同类任务立刻受益。</p><h3 id="slow-loop-小时级" tabindex="-1">Slow Loop（小时级） <a class="header-anchor" href="#slow-loop-小时级" aria-label="Permalink to &quot;Slow Loop（小时级）&quot;">​</a></h3><p>在用户不活跃时段（凌晨 2-6 点等），通过 <strong>LoRA 微调 + RL-PRM</strong> 做梯度级模型更新。<strong>OMLS 调度器</strong>监控系统不活跃状态和日历数据来判断&quot;什么时候可以安全跑训练&quot;。</p><h3 id="双环互增强" tabindex="-1">双环互增强 <a class="header-anchor" href="#双环互增强" aria-label="Permalink to &quot;双环互增强&quot;">​</a></h3><p>更好模型策略 → 更好执行轨迹 → 更高质量 Skill → 更丰富 Skill 提供更好训练数据 → 循环往复。</p><h3 id="数据版本控制" tabindex="-1">数据版本控制 <a class="header-anchor" href="#数据版本控制" aria-label="Permalink to &quot;数据版本控制&quot;">​</a></h3><p>分离 <strong>support</strong>（训练用）和 <strong>query</strong>（评测用）数据，防止&quot;用考试题训练&quot;的污染。</p><h3 id="实证增益" tabindex="-1">实证增益 <a class="header-anchor" href="#实证增益" aria-label="Permalink to &quot;实证增益&quot;">​</a></h3><ul><li>Kimi-K2.5 准确率：<strong>21.4% → 40.6%</strong></li><li>复合鲁棒性 <strong>+18.3%</strong></li></ul><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>紧密绑定 OpenClaw 平台</li><li><strong>Slow Loop 需要模型权限</strong> —— 闭源 API 模型无法使用</li><li>Skill 合成质量依赖 LLM Evolver 自身判断</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.60</td><td>论文 + 开源，已在 OpenClaw 平台部署</td></tr><tr><td>创新性</td><td>0.80</td><td>双环架构 + 数据版本控制是独有设计</td></tr><tr><td>落地程度</td><td>0.50</td><td>仅 OpenClaw 平台</td></tr><tr><td>生态活跃度</td><td>0.70</td><td>3.5K+ ★</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.65</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2603.17187" target="_blank" rel="noreferrer">MetaClaw 论文</a></li><li><a href="https://github.com/aiming-lab/MetaClaw" target="_blank" rel="noreferrer">GitHub</a></li></ul>',33)])])}const g=t(l,[["render",n]]);export{c as __pageData,g as default};
